"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[47723],{62958(e,n,i){i.r(n),i.d(n,{assets:()=>c,contentTitle:()=>o,default:()=>h,frontMatter:()=>s,metadata:()=>t,toc:()=>l});let t=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/fair-value-hedge-of-foreign-currency-25afdd6d0e","title":"Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)","description":"September 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments/Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 9 Financial Instruments","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/fair-value-hedge-of-foreign-currency-25afdd6d0e","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/fair-value-hedge-of-foreign-currency-25afdd6d0e","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":3,"frontMatter":{"id":"fair-value-hedge-of-foreign-currency-25afdd6d0e","title":"Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/fair-value-hedge-of-foreign-currency-25afdd6d0e","sidebar_position":3},"sidebar":"knowledgeSidebar","previous":{"title":"Curing of a Credit-impaired Financial Asset (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/curing-of-a-credit-impaired-financia-59893ce139"},"next":{"title":"Hedging Variability in Cash Flows due to Real Interest Rates (IFRS 9)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/hedging-variability-in-cash-flows-du-5d82ceea22"}}');var a=i(74848),r=i(28453);let s={id:"fair-value-hedge-of-foreign-currency-25afdd6d0e",title:"Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-9-financial-instruments-51656c8be6/fair-value-hedge-of-foreign-currency-25afdd6d0e",sidebar_position:3},o="Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)",c={},l=[{value:"Hedge accounting requirements in IFRS 9",id:"hedge-accounting-requirements-in-ifrs-9",level:2},{value:"Can an entity have exposure to foreign currency risk on a non-financial asset held for consumption that could affect profit or loss?",id:"can-an-entity-have-exposure-to-foreign-currency-risk-on-a-non-financial-asset-held-for-consumption-that-could-affect-profit-or-loss",level:2},{value:"If an entity has exposure to foreign currency risk on a non-financial asset, is it a separately identifiable and reliably measurable risk component?",id:"if-an-entity-has-exposure-to-foreign-currency-risk-on-a-non-financial-asset-is-it-a-separately-identifiable-and-reliably-measurable-risk-component",level:2},{value:"Can the designation of foreign currency risk on a non-financial asset held for consumption be consistent with an entity\u2019s risk management activities?",id:"can-the-designation-of-foreign-currency-risk-on-a-non-financial-asset-held-for-consumption-be-consistent-with-an-entitys-risk-management-activities",level:2},{value:"Other considerations",id:"other-considerations",level:2}];function d(e){let n={h1:"h1",h2:"h2",header:"header",p:"p",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"fair-value-hedge-of-foreign-currency-risk-on-non-financial-assets-ifrs-9",children:"Fair Value Hedge of Foreign Currency Risk on Non-Financial Assets (IFRS 9)"})}),"\n",(0,a.jsx)(n.p,{children:"September 2019\nThe Committee received two requests about fair value hedge accounting applying IFRS 9. Both requests asked whether foreign currency risk can be a separately identifiable and reliably measurable risk component of a non-financial asset held for consumption that an entity can designate as the hedged item in a fair value hedge accounting relationship."}),"\n",(0,a.jsx)(n.h2,{id:"hedge-accounting-requirements-in-ifrs-9",children:"Hedge accounting requirements in IFRS 9"}),"\n",(0,a.jsx)(n.p,{children:"The objective of hedge accounting is to represent, in the financial statements, the effect of an entity\u2019s risk management activities that use financial instruments to manage exposures arising from particular risks that could affect profit or loss (or, in some cases, other comprehensive income) (paragraph 6.1.1 of IFRS 9)."}),"\n",(0,a.jsx)(n.p,{children:"If all the qualifying criteria specified in IFRS 9 are met, an entity may choose to designate a hedging relationship between a hedging instrument and a hedged item. One type of hedge accounting relationship is a fair value hedge, in which an entity hedges the exposure to changes in fair value of a hedged item that is attributable to a particular risk and could affect profit or loss."}),"\n",(0,a.jsx)(n.p,{children:"An entity may designate an item in its entirety, or a component of an item, as a hedged item. A risk component may be designated as the hedged item if, based on an assessment within the context of the particular market structure, that risk component is separately identifiable and reliably measurable."}),"\n",(0,a.jsx)(n.p,{children:"In considering the request, the Committee assessed the following:"}),"\n",(0,a.jsx)(n.h2,{id:"can-an-entity-have-exposure-to-foreign-currency-risk-on-a-non-financial-asset-held-for-consumption-that-could-affect-profit-or-loss",children:"Can an entity have exposure to foreign currency risk on a non-financial asset held for consumption that could affect profit or loss?"}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 6.5.2(a) of IFRS 9 describes a fair value hedge as \u2018a hedge of the exposure to changes in fair value of a recognised asset or liability or an unrecognised firmcommitment, or a component of any such item, that is attributable to a particular risk and could affect profit or loss\u2019."}),"\n",(0,a.jsx)(n.p,{children:"Therefore, in the context of a fair value hedge, foreign currency risk arises when changes in exchange rates result in changes in the fair value of the underlying item that could affect profit or loss."}),"\n",(0,a.jsx)(n.p,{children:"Depending on the particular facts and circumstances, a non-financial asset might be priced\u2014and its fair value determined\u2014only in one currency at a global level and that currency is not the entity\u2019s functional currency. If the fair value of a non-financial asset is determined in a foreign currency, applying IAS 21 The Effects of Changes in Foreign Exchange Rates, the measure of fair value that could affect profit or loss is the fair value translated into an entity\u2019s functional currency (translated fair value). The translated fair value of such a non-financial asset would change as a result of changes in the applicable exchange rate in a given period, even if the fair value (determined in the foreign currency) were to remain constant. The Committee therefore observed that in such circumstances an entity is exposed to foreign currency risk."}),"\n",(0,a.jsx)(n.p,{children:"IFRS 9 does not require changes in fair value to be expected to affect profit or loss but, rather, that those changes could affect profit or loss. The Committee observed that changes in fair value of a non-financial asset held for consumption could affect profit or loss if, for example, the entity were to sell the asset before the end of the asset\u2019s economic life."}),"\n",(0,a.jsx)(n.p,{children:"Consequently, the Committee concluded that, depending on the particular facts and circumstances, it is possible for an entity to have exposure to foreign currency risk on a non-financial asset held for consumption that could affect profit or loss. This would be the case when, at a global level, the fair value of a non-financial asset is determined only in one currency and that currency is not the entity\u2019s functional currency."}),"\n",(0,a.jsx)(n.h2,{id:"if-an-entity-has-exposure-to-foreign-currency-risk-on-a-non-financial-asset-is-it-a-separately-identifiable-and-reliably-measurable-risk-component",children:"If an entity has exposure to foreign currency risk on a non-financial asset, is it a separately identifiable and reliably measurable risk component?"}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 6.3.7 of IFRS 9 permits an entity to designate a risk component of an item as the hedged item if, \u2018based on an assessment within the context of the particular market structure, the risk component is separately identifiable and reliably measurable\u2019."}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 82 of IAS 39 Financial Instruments: Recognition and Measurement permits the designation of non-financial items as hedged items only for a) foreign currency risks, or b) in their entirety for all risks, \u2018because of the difficulty of isolating and measuring the appropriate portion of the cash flows or fair value changes attributable to specific risks other than foreign currency risks\u2019. Paragraph BC6.176 of IFRS 9 indicates that, in developing the hedge accounting requirements in IFRS 9, the Board did not change its view that there are situations in which foreign currency risk can be separately identified and reliably measured. That paragraph states that the Board \u2018learned from its outreach activities that there are circumstances in which entities are able to identify and measure many risk components (not only foreign currency risk) of non-financial items with sufficient reliability\u2019."}),"\n",(0,a.jsx)(n.p,{children:"Consequently, the Committee concluded that foreign currency risk can be a separately identifiable and reliably measurable risk component of a non-financial asset. Whether that is the case will depend on an assessment of the particular facts and circumstances within the context of the particular market structure."}),"\n",(0,a.jsx)(n.p,{children:"The Committee observed that foreign currency risk is separately identifiable and reliably measurable when the risk being hedged relates to changes in fair value arising from translation into an entity\u2019s functional currency of fair value that, based on an assessment within the context of the particular market structure, is determined globally only in one currency and that currency is not the entity\u2019s functional currency. The Committee noted, however, that the fact that market transactions are commonly settled in a particular currency does not necessarily mean that this is the currency in which the non-financial asset is priced\u2014and thus the currency in which its fair value is determined."}),"\n",(0,a.jsx)(n.h2,{id:"can-the-designation-of-foreign-currency-risk-on-a-non-financial-asset-held-for-consumption-be-consistent-with-an-entitys-risk-management-activities",children:"Can the designation of foreign currency risk on a non-financial asset held for consumption be consistent with an entity\u2019s risk management activities?"}),"\n",(0,a.jsx)(n.p,{children:"Paragraph 6.4.1(b) of IFRS 9 requires that, at the inception of a hedging relationship, \u2018there is formal designation and documentation of the hedging relationship and the entity\u2019s risk management objective and strategy for undertaking the hedge\u2019. Accordingly, the Committee observed that, applying IFRS 9, an entity can apply hedge accounting only if it is consistent with the entity\u2019s risk management objective and strategy for managing its exposure. An entity therefore cannot apply hedge accounting solely on the grounds that it identifies items in its statement of financial position that are measured differently but are subject to the same type of risk."}),"\n",(0,a.jsx)(n.p,{children:"To the extent that an entity intends to consume a non-financial asset (rather than to sell it), the Committee observed that changes in the fair value of the non-financial asset may be of limited significance to the entity. In such cases, an entity is unlikely to be managing and using hedging instruments to hedge risk exposures on the non-financial asset and, in that case, it cannot apply hedge accounting."}),"\n",(0,a.jsx)(n.p,{children:"The Committee expects that an entity would manage and hedge exposure to foreign currency risk on the fair value of non-financial assets held for consumption only in very limited circumstances\u2014in such circumstances, an entity would use hedging instruments to hedge only foreign currency risk exposure that it expects will affect profit or loss. This may be the case, for example, if (a) the entity expects to sell the non-financial asset (eg an item of property, plant and equipment) part-way through its economic life; (b) the expected residual value of the asset at the date of expected sale is significant; and (c) the entity manages and uses hedging instruments to hedge the foreign currency risk exposure only on the residual value of the asset."}),"\n",(0,a.jsx)(n.p,{children:"Furthermore, the Committee observed that risk management activities that aim only to reduce foreign exchange volatility arising from translating a financial liability denominated in a foreign currency applying IAS 21 are inconsistent with the designation of foreign exchange risk on a non-financial asset as the hedged item in a fair value hedge accounting relationship. In such circumstances, the entity is managing the foreign currency risk exposure arising on the financial liability, rather than managing the risk exposure arising on the non-financial asset."}),"\n",(0,a.jsx)(n.h2,{id:"other-considerations",children:"Other considerations"}),"\n",(0,a.jsx)(n.p,{children:"An entity applies all other applicable requirements in IFRS 9 in determining whether it can apply fair value hedge accounting in its particular circumstances, including requirements related to the designation of the hedged item and hedging instrument, and hedge effectiveness. For example, an entity would consider how its hedge accounting designation addresses any differences in the size, depreciation/amortisation pattern and expected sale/maturity of the hedged item and the hedging instrument."}),"\n",(0,a.jsx)(n.p,{children:"For any risk exposure for which an entity elects to apply hedge accounting, the entity also makes the disclosures required by IFRS 7 Financial Instruments: Disclosures related to hedge accounting. The Committee noted, in particular, that paragraphs 22A\u201322C of IFRS 7 require the disclosure of information about an entity\u2019s risk management strategy and how it is applied to manage risk."}),"\n",(0,a.jsx)(n.p,{children:"The Committee concluded that the principles and requirements in IFRS 9 provide an adequate basis for an entity to determine whether foreign currency risk can be a separately identifiable and reliably measurable risk component of a non-financial asset held for consumption that an entity can designate as the hedged item in a fair value hedge accounting relationship. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function h(e={}){let{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,n,i){i.d(n,{R:()=>s,x:()=>o});var t=i(96540);let a={},r=t.createContext(a);function s(e){let n=t.useContext(r);return t.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),t.createElement(r.Provider,{value:n},e.children)}}}]);